import{_ as o,o as s,c as a,ak as i}from"./chunks/framework.DiS-pR0X.js";const p=JSON.parse('{"title":"Lista de comandos Linux útiles para comprobar la seguridad e integridad del sistema:","description":"","frontmatter":{},"headers":[],"relativePath":"linux/linux/seguridad.md","filePath":"linux/linux/seguridad.md","lastUpdated":1775585594000}'),r={name:"linux/linux/seguridad.md"};function d(n,e,c,l,t,u){return s(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="lista-de-comandos-linux-utiles-para-comprobar-la-seguridad-e-integridad-del-sistema" tabindex="-1">Lista de comandos Linux útiles para comprobar la seguridad e integridad del sistema: <a class="header-anchor" href="#lista-de-comandos-linux-utiles-para-comprobar-la-seguridad-e-integridad-del-sistema" aria-label="Permalink to “Lista de comandos Linux útiles para comprobar la seguridad e integridad del sistema:”">​</a></h1><h2 id="_1-auditoria-de-usuarios-y-permisos" tabindex="-1">1. <strong>Auditoría de usuarios y permisos</strong> <a class="header-anchor" href="#_1-auditoria-de-usuarios-y-permisos" aria-label="Permalink to “1. Auditoría de usuarios y permisos”">​</a></h2><ul><li><p><strong><code>cat /etc/passwd</code></strong>: Verifica los usuarios del sistema.</p></li><li><p><strong><code>cat /etc/shadow</code></strong>: Revisa las contraseñas encriptadas (requiere permisos de root).</p></li><li><p><strong><code>sudo awk -F: &#39;($3 == 0) {print}&#39; /etc/passwd</code></strong>: Busca cuentas con UID 0 (root).</p></li><li><p><strong><code>ls -l /etc/passwd /etc/shadow</code></strong>: Verifica los permisos de los archivos críticos.</p></li><li><p><strong><code>sudo find / -perm -4000 -o -perm -2000</code></strong>: Busca archivos con permisos SUID o SGID.</p></li><li><p><strong><code>cat /etc/sudoers | grep -v &#39;#&#39;</code></strong>: Listar usuarios con privilegios de superusuario</p></li><li><p><strong><code>last</code></strong>: Ver los ultimos accesos al sistema</p></li><li><p><strong><code>who w</code></strong> Lista conexiones activas SSH</p></li><li><p><strong><code>journalctl -xe | grep &quot;Failed password&quot;</code></strong> Inicios de sesión fallidos.</p></li><li><p><strong><code>find /etc -type f -mtime -1 # Archivos modificados en las últimas 24 horas</code></strong> Cambios recientes en archivos del sistema*</p></li></ul><h2 id="_2-verificacion-de-servicios-y-puertos-abiertos" tabindex="-1">2. <strong>Verificación de servicios y puertos abiertos</strong> <a class="header-anchor" href="#_2-verificacion-de-servicios-y-puertos-abiertos" aria-label="Permalink to “2. Verificación de servicios y puertos abiertos”">​</a></h2><ul><li><p><strong><code>sudo netstat -tuln</code></strong>: Lista los puertos abiertos y los servicios asociados.</p></li><li><p><strong><code>sudo ss -tuln</code></strong>: Alternativa moderna a <code>netstat</code>.</p></li><li><p><strong><code>sudo lsof -i</code></strong>: Muestra los archivos abiertos relacionados con la red. <code>sudo lsof -i -P -n</code>: Verificar conexiones entrantes y salientes</p></li><li><p><strong><code>sudo nmap localhost</code></strong>: Escanea los puertos locales (requiere instalación de <code>nmap</code>). <code>sudo nmap -sS -p- localhost</code></p></li></ul><h2 id="_3-monitoreo-de-procesos" tabindex="-1">3. <strong>Monitoreo de procesos</strong> <a class="header-anchor" href="#_3-monitoreo-de-procesos" aria-label="Permalink to “3. Monitoreo de procesos”">​</a></h2><ul><li><p><strong><code>ps aux</code></strong>: Lista todos los procesos en ejecución. <code>ps aux --sort=-%cpu</code>: Procesos sospechosos <code>ps -U root -u root u</code>: Procesos ejecutandose como root</p></li><li><p><strong><code>top</code> o <code>htop</code></strong>: Monitorea el uso de recursos y procesos en tiempo real.</p></li><li><p><strong><code>sudo pstree</code></strong>: Muestra los procesos en forma de árbol.</p></li></ul><h2 id="_4-verificacion-de-integridad-de-archivos" tabindex="-1">4. <strong>Verificación de integridad de archivos</strong> <a class="header-anchor" href="#_4-verificacion-de-integridad-de-archivos" aria-label="Permalink to “4. Verificación de integridad de archivos”">​</a></h2><ul><li><p><strong><code>sudo debsums</code></strong> (en Debian/Ubuntu): Verifica la integridad de los paquetes instalados.</p></li><li><p><strong><code>sudo rpm -Va</code></strong> (en RedHat/CentOS): Verifica la integridad de los paquetes RPM.</p></li><li><p><strong><code>sudo tripwire --check</code></strong>: Si tienes Tripwire instalado, verifica cambios en los archivos del sistema.</p></li><li><p><strong><code>sudo aide --check</code></strong>: Similar a Tripwire, verifica la integridad del sistema con AIDE.</p></li></ul><h2 id="_5-revision-de-logs" tabindex="-1">5. <strong>Revisión de logs</strong> <a class="header-anchor" href="#_5-revision-de-logs" aria-label="Permalink to “5. Revisión de logs”">​</a></h2><ul><li><p><strong><code>sudo cat /var/log/auth.log</code></strong> (o <code>/var/log/secure</code> en RedHat): Revisa intentos de autenticación.</p></li><li><p><strong><code>sudo grep &quot;Failed&quot; /var/log/auth.log</code></strong>: Busca intentos fallidos de inicio de sesión.</p></li><li><p><strong><code>sudo tail -f /var/log/syslog</code></strong>: Monitorea los logs en tiempo real.</p></li><li><p><strong><code>sudo journalctl -xe</code></strong>: Revisa logs del sistema con <code>systemd</code>.</p></li></ul><h2 id="_6-verificacion-de-actualizaciones-y-parches" tabindex="-1">6. <strong>Verificación de actualizaciones y parches</strong> <a class="header-anchor" href="#_6-verificacion-de-actualizaciones-y-parches" aria-label="Permalink to “6. Verificación de actualizaciones y parches”">​</a></h2><ul><li><p><strong><code>sudo apt list --upgradable</code></strong> (en Debian/Ubuntu): Lista paquetes que necesitan actualización.</p></li><li><p><strong><code>sudo yum check-update</code></strong> (en RedHat/CentOS): Verifica actualizaciones disponibles.</p></li><li><p><strong><code>sudo unattended-upgrades --dry-run</code></strong>: Simula la instalación de actualizaciones de seguridad.</p></li></ul><h2 id="_7-revision-de-firewall" tabindex="-1">7. <strong>Revisión de firewall</strong> <a class="header-anchor" href="#_7-revision-de-firewall" aria-label="Permalink to “7. Revisión de firewall”">​</a></h2><ul><li><p><strong><code>sudo ufw status</code></strong>: Verifica el estado del firewall UFW (en Ubuntu).</p></li><li><p><strong><code>sudo iptables -L -v -n</code></strong>: Lista las reglas de iptables.</p></li><li><p><strong><code>sudo firewall-cmd --list-all</code></strong>: Verifica las reglas de firewalld (en RedHat/CentOS).</p></li></ul><h2 id="_8-escaneo-de-malware" tabindex="-1">8. <strong>Escaneo de malware</strong> <a class="header-anchor" href="#_8-escaneo-de-malware" aria-label="Permalink to “8. Escaneo de malware”">​</a></h2><ul><li><p><strong><code>sudo clamscan -r /</code></strong>: Escanea el sistema en busca de malware con ClamAV.</p></li><li><p><strong><code>sudo rkhunter --check</code></strong>: Ejecuta un escaneo con Rootkit Hunter.</p></li><li><p><strong><code>sudo chkrootkit</code></strong>: Busca rootkits en el sistema.</p></li></ul><h2 id="_9-revision-de-tareas-programadas" tabindex="-1">9. <strong>Revisión de tareas programadas</strong> <a class="header-anchor" href="#_9-revision-de-tareas-programadas" aria-label="Permalink to “9. Revisión de tareas programadas”">​</a></h2><ul><li><p><strong><code>crontab -l</code></strong>: Lista las tareas programadas del usuario actual.</p></li><li><p><strong><code>sudo cat /etc/crontab</code></strong>: Revisa las tareas programadas del sistema.</p></li><li><p><strong><code>sudo ls -l /etc/cron.*</code></strong>: Verifica los archivos en los directorios de cron.</p></li></ul><h2 id="_10-verificacion-de-modulos-del-kernel-cargados" tabindex="-1">10. <strong>Verificación de módulos del kernel cargados</strong> <a class="header-anchor" href="#_10-verificacion-de-modulos-del-kernel-cargados" aria-label="Permalink to “10. Verificación de módulos del kernel cargados”">​</a></h2><ul><li><p><strong><code>lsmod</code></strong>: Lista los módulos del kernel cargados.</p></li><li><p><strong><code>sudo modprobe -r &lt;módulo&gt;</code></strong>: Elimina un módulo sospechoso (si es seguro hacerlo).</p></li></ul><h2 id="_11-revision-de-variables-de-entorno" tabindex="-1">11. <strong>Revisión de variables de entorno</strong> <a class="header-anchor" href="#_11-revision-de-variables-de-entorno" aria-label="Permalink to “11. Revisión de variables de entorno”">​</a></h2><ul><li><p><strong><code>printenv</code></strong>: Muestra las variables de entorno actuales.</p></li><li><p><strong><code>echo $PATH</code></strong>: Verifica la variable PATH para asegurarte de que no haya rutas sospechosas.</p></li></ul><h2 id="_12-verificacion-de-conexiones-de-red-activas" tabindex="-1">12. <strong>Verificación de conexiones de red activas</strong> <a class="header-anchor" href="#_12-verificacion-de-conexiones-de-red-activas" aria-label="Permalink to “12. Verificación de conexiones de red activas”">​</a></h2><ul><li><p><strong><code>sudo netstat -anp</code></strong>: Muestra todas las conexiones de red y los procesos asociados.</p></li><li><p><strong><code>sudo lsof -i -n</code></strong>: Lista las conexiones de red y los archivos abiertos.</p></li></ul><h2 id="_13-revision-de-archivos-ocultos" tabindex="-1">13. <strong>Revisión de archivos ocultos</strong> <a class="header-anchor" href="#_13-revision-de-archivos-ocultos" aria-label="Permalink to “13. Revisión de archivos ocultos”">​</a></h2><ul><li><strong><code>sudo find / -name &quot;.*&quot; -ls</code></strong>: Busca archivos ocultos en el sistema.</li></ul><h2 id="_14-verificacion-de-selinux-apparmor" tabindex="-1">14. <strong>Verificación de SELinux/AppArmor</strong> <a class="header-anchor" href="#_14-verificacion-de-selinux-apparmor" aria-label="Permalink to “14. Verificación de SELinux/AppArmor”">​</a></h2><ul><li><p><strong><code>sestatus</code></strong>: Verifica el estado de SELinux.</p></li><li><p><strong><code>aa-status</code></strong>: Verifica el estado de AppArmor.</p></li></ul><h2 id="_15-revision-de-permisos-de-archivos-sensibles" tabindex="-1">15. <strong>Revisión de permisos de archivos sensibles</strong> <a class="header-anchor" href="#_15-revision-de-permisos-de-archivos-sensibles" aria-label="Permalink to “15. Revisión de permisos de archivos sensibles”">​</a></h2><ul><li><p><strong><code>sudo find / -type f -perm -o+w</code></strong>: Busca archivos con permisos de escritura para otros.</p></li><li><p><strong><code>sudo find / -type d -perm -o+w</code></strong>: Busca directorios con permisos de escritura para otros.</p></li></ul><h2 id="_16-verificacion-de-la-configuracion-ssh" tabindex="-1">16. <strong>Verificación de la configuración SSH</strong> <a class="header-anchor" href="#_16-verificacion-de-la-configuracion-ssh" aria-label="Permalink to “16. Verificación de la configuración SSH”">​</a></h2><ul><li><p><strong><code>sudo cat /etc/ssh/sshd_config</code></strong>: Revisa la configuración del servidor SSH.</p></li><li><p><strong><code>sudo grep PermitRootLogin /etc/ssh/sshd_config</code></strong>: Verifica si el login como root está permitido.</p></li></ul><h2 id="_17-revision-de-la-configuracion-de-sudo" tabindex="-1">17. <strong>Revisión de la configuración de sudo</strong> <a class="header-anchor" href="#_17-revision-de-la-configuracion-de-sudo" aria-label="Permalink to “17. Revisión de la configuración de sudo”">​</a></h2><ul><li><p><strong><code>sudo cat /etc/sudoers</code></strong>: Verifica los privilegios de sudo.</p></li><li><p><strong><code>sudo grep -r &quot;NOPASSWD&quot; /etc/sudoers*</code></strong>: Busca usuarios con permisos de sudo sin contraseña.</p></li></ul><h2 id="_18-verificacion-de-la-configuracion-de-pam" tabindex="-1">18. <strong>Verificación de la configuración de PAM</strong> <a class="header-anchor" href="#_18-verificacion-de-la-configuracion-de-pam" aria-label="Permalink to “18. Verificación de la configuración de PAM”">​</a></h2><ul><li><strong><code>cat /etc/pam.d/common-auth</code></strong>: Revisa la configuración de autenticación PAM.</li></ul><h2 id="_19-revision-de-la-configuracion-de-sysctl" tabindex="-1">19. <strong>Revisión de la configuración de sysctl</strong> <a class="header-anchor" href="#_19-revision-de-la-configuracion-de-sysctl" aria-label="Permalink to “19. Revisión de la configuración de sysctl”">​</a></h2><ul><li><strong><code>sudo sysctl -a</code></strong>: Muestra todas las configuraciones de seguridad del kernel.</li></ul><h2 id="_20-escaneo-de-vulnerabilidades" tabindex="-1">20. <strong>Escaneo de vulnerabilidades</strong> <a class="header-anchor" href="#_20-escaneo-de-vulnerabilidades" aria-label="Permalink to “20. Escaneo de vulnerabilidades”">​</a></h2><ul><li><strong><code>sudo lynis audit system</code></strong>: Ejecuta un escaneo de seguridad con Lynis.</li></ul><hr>',42)])])}const h=o(r,[["render",d]]);export{p as __pageData,h as default};
